const isAB = chunk instanceof ArrayBuffer;
const buf = Buffer.from(
  isAB ? chunk : chunk.buffer,
  isAB ? 0 : (chunk as Uint8Array).byteOffset,
  isAB ? chunk.byteLength : (chunk as Uint8Array).byteLength,
);
this.chunkQueue.push(buf);
this.queuedBytes += chunk.byteLength;
this.queueDepth++;

const ab = pixels.buffer;
if (pixels.byteOffset === 0 && pixels.byteLength === ab.byteLength) {
  this.port.postMessage(msg, [ab]);
  return;
}
const exact = ab.slice(pixels.byteOffset, pixels.byteOffset + pixels.byteLength);
msg.pixels = exact;
this.port.postMessage(msg, [exact]);

private adaptiveHwm(): number {
  const factor = Math.max(0.6, Math.min(2.0, 120 / (this.pushLatencyEma + 10)));
  return Math.floor(HWM_BASE * factor);
}

const t0 = performance.now();
await decoder.push(chunk);
const pushMs = performance.now() - t0;
this.pushLatencyEma = HWM_EMA_ALPHA * pushMs + (1 - HWM_EMA_ALPHA) * this.pushLatencyEma;

this.maybePostDrain();

const t0 = performance.now();
await encoder.pushPixels(entry.chunk, entry.region);
const pushMs = performance.now() - t0;
this.pushLatencyEma = HWM_EMA_ALPHA * pushMs + (1 - HWM_EMA_ALPHA) * this.pushLatencyEma;

if (this.cancelled || this.isErrored()) return;
this.maybePostDrain();

private postChunk(msg: MsgEncodeChunk, chunk: Buffer): void {
  const ab = chunk.buffer;
  if (chunk.byteOffset === 0 && chunk.byteLength === ab.byteLength) {
    this.port.postMessage(msg, [ab]);
  } else {
    const exact = ab.slice(chunk.byteOffset, chunk.byteOffset + chunk.byteLength);
    msg.chunk = exact as unknown as ArrayBuffer;
    this.port.postMessage(msg, [exact]);
  }
}

function hasAnySession(sessionId: string): boolean {
  return (
    decodeSessions.has(sessionId) ||
    encodeSessions.has(sessionId) ||
    pendingDecodeStarts.has(sessionId) ||
    pendingEncodeStarts.has(sessionId) ||
    queuedDecodeMessages.has(sessionId) ||
    queuedEncodeMessages.has(sessionId)
  );
}

if (code !== 0) {
  for (const h of messageHandlers.slice()) {
    h({
      type: "worker_error",
      ...
    });
  }
  for (const h of messageHandlers.slice()) {
    h({
      type: "worker_shutdown_ack",
    });
  }
}

async function waitFor(predicate: () => boolean): Promise<void> {
  const started = Date.now();
  while (!predicate()) {
    if (Date.now() - started > 500) {
      throw new Error("timed out waiting for handler");
    }
    await new Promise((resolve) => setTimeout(resolve, 1));
  }
}
